import{_ as a,c as i,o as l,V as e}from"./chunks/framework.9b555ede.js";const p=JSON.parse('{"title":"如何更优雅的编写Java代码","description":"如何更优雅的编写Java代码","frontmatter":{"title":"如何更优雅的编写Java代码","author":"nkxrb","avatar":"http://cdnblog.nkxrb.xyz/images/home/avatar.png","authorLink":"blog.nkxrb.xyz","authorAbout":"nkxrb","authorDesc":"nkxrb","photos":"http://cdnblog.nkxrb.xyz/images/archives/java5.jpeg","categories":"serve","tags":["java"],"date":"2019-01-05T21:16:01.000Z","comments":true,"keywords":"代码规范","description":"如何更优雅的编写Java代码"},"headers":[],"relativePath":"original/【设计】Java编码规范.md","filePath":"original/【设计】Java编码规范.md","lastUpdated":1640536454000}'),t={name:"original/【设计】Java编码规范.md"},r=e('<p>当面对复杂多变的业务时，许多程序员难免会使用if-else 多层嵌套，或复制此方法，重命名，冗余代码繁多，可读性差。。。</p><p>其实大多数原因是因为我们日常编写Java时的习惯导致的，具备良好的编码习惯，可以为后续业务的进展减少许多麻烦，同时也为未来系统重构奠定了基础。</p><p>那么，如何养成好的编码习惯呢？什么样的习惯算是好习惯呢？</p><p>这样的规定没有绝对，因项目的走向不同而不同。以下习惯仅供参考 ∩_∩！</p><h2 id="必要的-editutil-项目组自定义的" tabindex="-1">必要的 EditUtil （项目组自定义的） <a class="header-anchor" href="#必要的-editutil-项目组自定义的" aria-label="Permalink to &quot;必要的 EditUtil （项目组自定义的）&quot;">​</a></h2><p>项目组应建立一套通用的工具类，用于日常编写代码时，处理常用功能的Util</p><ul><li>统一的数据类型转化</li><li>判空（大多程序员容易犯的错误，忘记判空）</li><li>对象比较大小</li><li>hash</li><li>UUID获取</li><li>正则校验</li><li>编码转换</li><li>加解密 ...</li></ul><h2 id="静态常量-commonstatic" tabindex="-1">静态常量 CommonStatic <a class="header-anchor" href="#静态常量-commonstatic" aria-label="Permalink to &quot;静态常量 CommonStatic&quot;">​</a></h2><p>系统经常使用到的静态常量存储</p><ul><li>系统初始值</li><li>转义字典</li><li>正则表达式 ...</li></ul><h2 id="出入参统一封装类" tabindex="-1">出入参统一封装类 <a class="header-anchor" href="#出入参统一封装类" aria-label="Permalink to &quot;出入参统一封装类&quot;">​</a></h2><ul><li>code(响应码)，项目组尽可能统一下响应码级别</li><li>msg(响应信息)</li><li>rows(响应数据)</li><li>total(用于分页时的总记录数)</li></ul><h2 id="命名规则" tabindex="-1">命名规则 <a class="header-anchor" href="#命名规则" aria-label="Permalink to &quot;命名规则&quot;">​</a></h2><ul><li>意义明确！！！</li><li>注意大小写</li><li>无论驼峰还是下划线，一定要统一统一</li><li>变量（名词）、方法（动词+【名词】）</li></ul><h2 id="避免无用的变量声明-提高垃圾回收效率" tabindex="-1">避免无用的变量声明，提高垃圾回收效率 <a class="header-anchor" href="#避免无用的变量声明-提高垃圾回收效率" aria-label="Permalink to &quot;避免无用的变量声明，提高垃圾回收效率&quot;">​</a></h2><h2 id="关于异常的处理" tabindex="-1">关于异常的处理 <a class="header-anchor" href="#关于异常的处理" aria-label="Permalink to &quot;关于异常的处理&quot;">​</a></h2><ul><li>try块放到了事务代码中，catch异常后，如果需要回滚事务，必须手动回滚事务</li><li>在finally块必须对文件io进行关闭</li><li>不能在finally使用return，fanally块中的return返回方法结束执行，不会再执行 try 块中的 return 语句</li><li>循坏体中避免不必要的try-catch操作</li></ul><h2 id="datetimeutil" tabindex="-1">DateTimeUtil <a class="header-anchor" href="#datetimeutil" aria-label="Permalink to &quot;DateTimeUtil&quot;">​</a></h2><p>对于日期时间的统一处理，注意格式规范统一</p><h2 id="分页处理" tabindex="-1">分页处理 <a class="header-anchor" href="#分页处理" aria-label="Permalink to &quot;分页处理&quot;">​</a></h2><ul><li>注意分页的效率</li><li>注意判断前端传来的参数校验，避免大批量数据的查询</li></ul><h2 id="ifelse的嵌套不能超过3层" tabindex="-1">ifelse的嵌套不能超过3层 <a class="header-anchor" href="#ifelse的嵌套不能超过3层" aria-label="Permalink to &quot;ifelse的嵌套不能超过3层&quot;">​</a></h2><ul><li>可以考虑设计模式，抽取父类，子类，多实现等方式</li></ul><h2 id="服务器相关的配置集中管理-避免误操导致的灾难性后果" tabindex="-1">服务器相关的配置集中管理，避免误操导致的灾难性后果 <a class="header-anchor" href="#服务器相关的配置集中管理-避免误操导致的灾难性后果" aria-label="Permalink to &quot;服务器相关的配置集中管理，避免误操导致的灾难性后果&quot;">​</a></h2><ul><li>使用远程获取配置的方式，而不是在代码中硬编码</li></ul>',25),o=[r];function n(h,s,c,d,u,m){return l(),i("div",null,o)}const b=a(t,[["render",n]]);export{p as __pageData,b as default};
